.darma-loader-darma-custom-611 {color: var(--loader-color, #9333ea);
   width: 80px;
   aspect-ratio: 1;
   padding: 10px;
   box-sizing: border-box;
   background: currentColor;
   display: grid;
   filter: blur(5px) contrast(15) hue-rotate(250deg);
   mix-blend-mode: darken;
}
.darma-loader-darma-custom-611:before, .darma-loader-darma-custom-611:after  {
  content: "";
   margin: 5px;
   border-radius: 50%;
   background: #ff00ff;
   grid-area: 1/1;
   -webkit-mask-size:100% 20px,100% 100%;
   -webkit-mask-repeat:no-repeat;
   -webkit-mask-composite:destination-out;
   mask-composite:exclude;
}
.darma-loader-darma-custom-611:before  {
  -webkit-mask-image: linear-gradient(currentColor 0 0), linear-gradient(currentColor 0 0);
   animation: darma-loader-darma-custom-611-l8-1 2s infinite;
}
.darma-loader-darma-custom-611:after  {
  -webkit-mask-image: linear-gradient(currentColor 0 0);
   animation: darma-loader-darma-custom-611-l8-1 2s infinite, darma-loader-darma-custom-611-l8-2 .5s infinite cubic-bezier(0.5,200,0.5,-200);
}
@keyframes darma-loader-darma-custom-611-l8-1 {
  0% {-webkit-mask-position:0 20% ,0 0}
20% {-webkit-mask-position:0 80% ,0 0}
40% {-webkit-mask-position:0 100%,0 0}
60% {-webkit-mask-position:0 0% ,0 0}
80% {-webkit-mask-position:0 35% ,0 0}
100% {-webkit-mask-position:0 0 ,0 0}
}
@keyframes darma-loader-darma-custom-611-l8-2 {
  100% {transform:translate(0.1px)}
}

